SELECT emission_value, gas_type
FROM emission_data
ORDER BY emission_value ASC;

SELECT year
FROM emission_years
WHERE is_leap_year = 1;

SELECT c.country_name, et.average_emission, et.trend_type
FROM countries c
JOIN emission_trends et ON c.country_id = et.country_id;

SELECT DISTINCT country_name, region 
FROM countries 
ORDER BY region;
